   434|async function withTimeout<T>(operation: () => Promise<T>, timeoutMs: number, label: string, fallbackValue: T): Promise<T> {
   435|  return await new Promise<T>((resolve, reject) => {
   436|    let settled = false;
   437|
   438|    const timeout = setTimeout(() => {
   439|      if (settled) {
   440|        return;
   441|      }
   442|
   443|      settled = true;
   444|      console.log('[Auth] Operation timed out:', label, timeoutMs, 'ms');
   445|      resolve(fallbackValue);
   446|    }, timeoutMs);
   447|
   448|    void operation()
   449|      .then((result) => {
   450|        if (settled) {
   451|          return;
   452|        }
   453|
   454|        settled = true;
   455|        clearTimeout(timeout);
   456|        resolve(result);
   457|      })
   458|      .catch((error) => {
   459|        if (settled) {
   460|          return;
   461|        }
   462|
   463|        settled = true;
   464|        clearTimeout(timeout);
   465|        reject(error);
   466|      });
   467|  });
